operation.add:
// EasyCheckout (oc-kit) — підтягуємо custom-поля для рендеру summary
// ПЕРЕД cart->clear() щоб session.data['order_id'] ще був актуальний
$okec_order_id = (int)($this->session->data['order_id'] ?? 0);
if ($okec_order_id) {
    $this->load->model('extension/easycheckout/order');
    $okec_fields = $this->model_extension_easycheckout_order->getCustomFields($okec_order_id);
    $this->session->data['okec_success_fields'] = $okec_fields;
}

// Pull-out з session — після cart->clear доступний тільки залишений flag
$data['oc_kit_easycheckout_fields'] = $this->session->data['okec_success_fields'] ?? [];
unset($this->session->data['okec_success_fields']);
// Lang strings — beremо з easycheckout/checkout мовного файла
$this->load->language('easycheckout/checkout');
$data['text_easycheckout_summary'] = $this->language->get('text_easycheckout_summary');
